sql:
SELECT u.username, up.permission
FROM users u
JOIN user_permissions up ON u.user_id = up.user_id;

SELECT id, age, native_country
FROM demographic_data
ORDER BY age DESC, id DESC;

SELECT demographic_data.age, income_data.hours_per_week
FROM demographic_data
INNER JOIN income_data ON demographic_data.id = income_data.demographic_id;

